category_counts = {}

def extract_categories(description):
    if not description:
        return []
    text = " " + description + " "
    patterns = [r" including ", r" in the categories of ", r" in the fields of ", r" destination for ", r" seeking ", r" services in ", r" specializes in ", r" specialize in ", r" mix of ", r" featuring ", r" encompassing "]
    best_start = -1
    for p in patterns:
        matches = list(re.finditer(p, text))
        if matches:
            last_match = matches[-1]
            if last_match.end() > best_start:
                best_start = last_match.end()
    if best_start == -1:
